import { useWS, useOrderlyContext } from '@orderly/sdk';

const CustomDataListener = () => {
  const { network } = useOrderlyContext();
  const ws = useWS();

  useEffect(() => {
    if (!ws || !network) return;

    // Example: Custom subscription to a specific topic
    const subscription = {
      topic: 'ticker',
      symbol: 'BTC-USD'
    };

    ws.send(JSON.stringify({
      method: 'subscribe',
      params: [subscription]
    }));

    // Handle incoming messages
    const handleMessage = (event) => {
      const data = JSON.parse(event.data);
      console.log('Custom WS Data:', data);
    };

    ws.addEventListener('message', handleMessage);

    return () => {
      ws.removeEventListener('message', handleMessage);
      // Unsubscribe logic if needed
    };
  }, [ws, network]);

  return <div>Listening for custom ticker data...</div>;
};

