import { NumeralWithCtx } from '@orderly.network/ui-positions';
import { useOrderlyContext } from '@orderly.network/sdk';
import Decimal from 'decimal.js';

export function LiquidationPriceDisplay({ position }) {
  const { account } = useOrderlyContext();

  const liqPrice = position.liquidationPrice;
  const markPrice = position.markPrice;

  // Calculate distance to liquidation
  const distance = liqPrice && markPrice 
    ? Math.abs(markPrice - liqPrice) / markPrice * 100 
    : 0;

  return (
    <div className="liquidation-info">
      <NumeralWithCtx
        value={liqPrice}
        rm={Decimal.ROUND_DOWN}
        className={distance < 10 ? 'warning' : 'normal'}
        prefix="Liq: "
        suffix=" USD"
      />
      <NumeralWithCtx
        value={distance}
        rm={Decimal.ROUND_HALF_UP}
        className="distance-to-liq"
        prefix="Distance: "
        suffix="%"
      />
    </div>
  );
}

