import React, { useState } from 'react';
import { ActionButton } from '@orderly.network/ui-transfer';
import { useWalletSubscription } from '@orderly.network/ui';

export const TransferActionExample = () => {
  const [state, setState] = useState('idle'); // 'idle' | 'signing' | 'trading'
  const { isConnected } = useWalletSubscription();

  const handleSignIn = async () => {
    setState('signing');
    // Simulate sign in logic
    await new Promise(r => setTimeout(r, 1000));
    setState('trading');
  };

  const handleEnableTrading = async () => {
    setState('trading');
    // Simulate enable trading logic
    await new Promise(r => setTimeout(r, 1000));
    setState('idle');
  };

  return (
    <div className="p-4 border rounded">
      <h3>Transfer Action Flow</h3>
      <ActionButton
        state={state}
        signIn={handleSignIn}
        enableTrading={handleEnableTrading}
        disabled={!isConnected}
      />
    </div>
  );
};

