export const SwapButton = () => {
  const [loading, setLoading] = useState(false);
  const { convert } = useConvert();
  const networkId = '1'; // Example Ethereum Mainnet

  const handleConvert = async (data: any) => {
    setLoading(true);
    try {
      await convert(data);
    } finally {
      setLoading(false);
    }
  };

  return (
    <ConvertAction
      networkId={networkId}
      disabled={loading}
      loading={loading}
      onConvert={handleConvert}
    />
  );
};

