import { WithdrawForm } from '@orderly.network/ui-transfer';
import { useWithdraw, useTokensInfo, useChain } from '@orderly.network/ui-sdk';

function WithdrawPage() {
  const { tokens } = useTokensInfo();
  const { chain } = useChain();
  const { withdraw, isPending } = useWithdraw();

  const handleSubmit = async (formData) => {
    await withdraw({
      token: formData.token,
      amount: formData.amount,
      destination: formData.destination,
    });
  };

  return (
    <div className="oui-p-4 oui-bg-white oui-rounded-lg">
      <WithdrawForm
        tokens={tokens}
        chain={chain}
        onSubmit={handleSubmit}
        isSubmitting={isPending}
        showWarning={true}
      />
    </div>
  );
}

